#include<bits/stdc++.h>
using namespace std;
int main()
{
	int a[100005],n,sum=0;
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+n+1);
	while(n)
	{
		if(n==1)
		{
			sum+=a[1];
			n=0;
		}
		else if(n==2)
		{
			sum+=a[2];
			n=0;
		}
		else if(n==3)
		{
			sum+=(a[1]+a[2]+a[3]);
			n=0;
		}
		else
		{
			if(2*a[2]>a[1]+a[n-1])
			{
				sum+=(a[n-1]+a[n])+2*a[1];
				n-=2;
			}
			else
			{
				sum+=(a[2]+a[1]+a[n]+a[2]);
				n-=2;
			}
		}
	} 
	cout<<sum;
	return 0;
}
